function a(){b();c();d();e()}function b(){console.log(`default lang = ${getDefaultLanguage()}`);console.log(`lang cookie  = ${getCookie('language')}`);console.log(`current site lang = ${getCurrentSiteLanguage()}`);console.log(`current path = ${getCurrentPath()}`);console.log(`curren site =${window.location.href}`);console.log(`browser prefers light = ${browserPrefersLight()}`);console.log(`theme cookie = ${getCookie('theme')}`);console.log(`device width = ${window.screen.width}px`);console.log(`menuStatus = ${getCookie('menuStatus')}`)}function c(){console.log('Cookies =');let A=document.cookie;A===''?console.log('No cookies found'):A.split(';').forEach(_=>{const[B,C]=_.split('=');console.log(`Cookie Name = '${B.trim()}', value= ${C}`)})}function d(){console.log('Local storage items =');if(localStorage.length===1)console.log('No items found in local storage.');else for(let i=0;i<localStorage.length;i++){const _a=localStorage.key(i);console.log(`Key: ${_a}, Value = ${localStorage.getItem(_a)}`)}}function e(){console.log('Session storage items =');if(sessionStorage.length===0)console.log('No items found in session storage.');else for(let i=0;i<sessionStorage.length;i++){const D=sessionStorage.key(i);console.log(`Key: ${D}, Value = ${sessionStorage.getItem(D)}`)}}
